.ulist {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.ulist__loading {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.ulist__skeleton {
  height: 3.5rem;
  background: linear-gradient(90deg, #f3f4f6 25%, #e5e7eb 50%, #f3f4f6 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s ease-in-out infinite;
  border-radius: 0.375rem;
}

@keyframes shimmer {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

.ulist__error {
  text-align: center;
  padding: 1.5rem;
  background: #fef2f2;
  border-radius: 0.5rem;
}

.ulist__error p {
  color: #ef4444;
  margin-bottom: 0.75rem;
  font-size: 0.875rem;
}

.ulist__retry {
  padding: 0.375rem 0.75rem;
  border: none;
  border-radius: 0.375rem;
  background: #ef4444;
  color: white;
  font-size: 0.8125rem;
  cursor: pointer;
}

.ulist__list {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.ulist__card {
  padding: 0.75rem 1rem;
  border: 1px solid #e5e7eb;
  border-radius: 0.375rem;
}

.ulist__name {
  font-weight: 500;
  font-size: 0.875rem;
}

.ulist__email {
  font-size: 0.8125rem;
  color: #6b7280;
}

.ulist__role {
  display: inline-block;
  margin-top: 0.25rem;
  padding: 0.125rem 0.5rem;
  background: #eff6ff;
  color: #3b82f6;
  font-size: 0.75rem;
  border-radius: 9999px;
}

