import React, { useState, useEffect, useCallback } from 'react';
import './styles.css';

interface User {
  id: number;
  name: string;
  email: string;
  role: string;
}

interface UserListProps {
  apiUrl: string;
}

export const UserList: React.FC<UserListProps> = ({ apiUrl }) => {
  const [users, setUsers] = useState<User[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [retryCount, setRetryCount] = useState(0);

  useEffect(() => {
    const controller = new AbortController();

    const fetchUsers = async () => {
      setIsLoading(true);
      setError(null);
      try {
        const response = await fetch(apiUrl, { signal: controller.signal });
        if (!response.ok) throw new Error(`HTTP error ${response.status}`);
        const data = await response.json();
        setUsers(data);
      } catch (err: any) {
        if (err.name !== 'AbortError') {
          setError(err.message || 'Failed to fetch users');
        }
      } finally {
        if (!controller.signal.aborted) {
          setIsLoading(false);
        }
      }
    };

    fetchUsers();

    return () => {
      controller.abort();
    };
  }, [apiUrl, retryCount]);

  const handleRetry = useCallback(() => {
    setRetryCount(c => c + 1);
  }, []);

  return (
    <div className="ulist">
      {isLoading && (
        <div data-testid="loading" className="ulist__loading">
          <div className="ulist__skeleton" />
          <div className="ulist__skeleton" />
          <div className="ulist__skeleton" />
        </div>
      )}

      {error && !isLoading && (
        <div data-testid="error" className="ulist__error">
          <p>{error}</p>
          <button data-testid="retry-btn" className="ulist__retry" onClick={handleRetry}>
            Retry
          </button>
        </div>
      )}

      {!isLoading && !error && (
        <div data-testid="user-list" className="ulist__list">
          {users.map(user => (
            <div key={user.id} data-testid={`user-${user.id}`} className="ulist__card">
              <div className="ulist__name">{user.name}</div>
              <div className="ulist__email">{user.email}</div>
              <span className="ulist__role">{user.role}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};
